from __future__ import annotations

from pathlib import Path
from typing import Any

import numpy as np

from substrate.core import read_json, stable_hash, write_json
from substrate.neuron.baseline import simulate_hh
from .metrics import detect_spikes, voltage_trace_similarity, spike_timing_score

EPHYS_SCHEMA = "substrate-external-ephys-v1"


def make_protocol(
    protocol_id: str,
    current_uA: float,
    duration_ms: float = 80.0,
    dt_ms: float = 0.025,
    pulse_start_ms: float = 10.0,
    pulse_end_ms: float = 60.0,
) -> dict[str, Any]:
    sim = simulate_hh(
        duration_ms=duration_ms,
        dt=dt_ms,
        current_uA=current_uA,
        pulse_start=pulse_start_ms,
        pulse_end=pulse_end_ms,
    )
    voltage = [float(row["v_mv"]) for row in sim["trace"]]
    return {
        "protocol_id": protocol_id,
        "current_uA": float(current_uA),
        "duration_ms": float(duration_ms),
        "dt_ms": float(dt_ms),
        "pulse_start_ms": float(pulse_start_ms),
        "pulse_end_ms": float(pulse_end_ms),
        "voltage_mv": voltage,
        "spike_times_ms": detect_spikes(voltage, dt_ms),
    }


def write_ephys_dataset(
    out: str | Path,
    source_name: str,
    cell_id: str,
    train_currents: list[float] | None = None,
    heldout_currents: list[float] | None = None,
    metadata: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if train_currents is None:
        train_currents = [5.0, 10.0, 15.0]
    if heldout_currents is None:
        heldout_currents = [7.5, 12.5, 17.5]
    protocols = []
    for idx, current in enumerate(train_currents):
        row = make_protocol(f"train_{idx}_I{current:g}", current)
        row["split"] = "train"
        protocols.append(row)
    for idx, current in enumerate(heldout_currents):
        row = make_protocol(f"heldout_{idx}_I{current:g}", current)
        row["split"] = "heldout"
        protocols.append(row)
    dataset = {
        "schema": EPHYS_SCHEMA,
        "source_name": source_name,
        "cell_id": cell_id,
        "metadata": metadata or {},
        "protocols": protocols,
    }
    dataset["source_hash"] = stable_hash(dataset)
    write_json(out, dataset)
    return dataset


def load_ephys_dataset(path: str | Path) -> dict[str, Any]:
    dataset = read_json(path)
    if dataset.get("schema") != EPHYS_SCHEMA:
        raise ValueError(f"Unsupported ephys schema: {dataset.get('schema')}")
    if "source_hash" not in dataset:
        dataset["source_hash"] = stable_hash(dataset)
    return dataset


def protocol_split(dataset: dict[str, Any], split: str) -> list[dict[str, Any]]:
    return [row for row in dataset["protocols"] if row.get("split") == split]


def fi_rows_from_protocols(protocols: list[dict[str, Any]]) -> list[dict[str, Any]]:
    rows = []
    for protocol in protocols:
        rows.append(
            {
                "current_uA": float(protocol["current_uA"]),
                "spike_count": len(protocol.get("spike_times_ms") or []),
                "rate_hz": len(protocol.get("spike_times_ms") or []) / max(float(protocol["duration_ms"]) / 1000.0, 1e-9),
            }
        )
    return rows


def estimate_gain_offset(train_protocols: list[dict[str, Any]]) -> dict[str, float]:
    """Fit simple current gain/offset using train spike counts and voltage traces.

    The canonical HH/NeuroML-style fixture is generated by the same current-clamp
    engine, so the identity transform should be recovered immediately. For real
    exported Allen/DANDI/NWB-style JSON, this falls back to a bounded grid search.
    """

    if not train_protocols:
        return {"current_gain": 1.0, "current_offset": 0.0, "loss": 0.0, "train_score": 1.0}

    def score_candidate(gain: float, offset: float) -> tuple[float, float]:
        scores = []
        for protocol in train_protocols:
            pred_current = float(gain) * float(protocol["current_uA"]) + float(offset)
            sim = make_protocol(
                "fit",
                pred_current,
                duration_ms=float(protocol["duration_ms"]),
                dt_ms=float(protocol["dt_ms"]),
                pulse_start_ms=float(protocol["pulse_start_ms"]),
                pulse_end_ms=float(protocol["pulse_end_ms"]),
            )
            voltage = voltage_trace_similarity(sim["voltage_mv"], protocol["voltage_mv"])
            spike = spike_timing_score(sim["spike_times_ms"], protocol.get("spike_times_ms") or [])
            scores.append(0.65 * voltage + 0.35 * spike)
        train_score = float(np.mean(scores))
        return 1.0 - train_score, train_score

    identity_loss, identity_score = score_candidate(1.0, 0.0)
    if identity_score >= 0.999999:
        return {"current_gain": 1.0, "current_offset": 0.0, "loss": float(identity_loss), "train_score": identity_score}

    gains = np.linspace(0.7, 1.3, 13)
    offsets = np.linspace(-2.0, 2.0, 17)
    best = {"current_gain": 1.0, "current_offset": 0.0, "loss": float(identity_loss), "train_score": identity_score}
    for gain in gains:
        for offset in offsets:
            loss, train_score = score_candidate(float(gain), float(offset))
            tie_break = 1e-6 * (abs(float(gain) - 1.0) + abs(float(offset)))
            best_tie = 1e-6 * (abs(best["current_gain"] - 1.0) + abs(best["current_offset"]))
            if loss + tie_break < best["loss"] + best_tie:
                best = {"current_gain": float(gain), "current_offset": float(offset), "loss": float(loss), "train_score": train_score}
    return best


def simulate_fitted_protocol(protocol: dict[str, Any], fit: dict[str, float]) -> dict[str, Any]:
    current = float(fit["current_gain"]) * float(protocol["current_uA"]) + float(fit["current_offset"])
    predicted = make_protocol(
        protocol_id=f"pred_{protocol['protocol_id']}",
        current_uA=current,
        duration_ms=float(protocol["duration_ms"]),
        dt_ms=float(protocol["dt_ms"]),
        pulse_start_ms=float(protocol["pulse_start_ms"]),
        pulse_end_ms=float(protocol["pulse_end_ms"]),
    )
    predicted["source_protocol_id"] = protocol["protocol_id"]
    return predicted
